package main

import (
	"flag"
	"fmt"
	"log"
	"net/http"
	"sync"
)

type Result struct {
	Err error
}

func makeRequest(url string, resChan chan<- Result) {
	resp, err := http.Get(url)
	if err != nil {
		resChan <- Result{Err: err}
		return
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		resChan <- Result{Err: fmt.Errorf("status code %d", resp.StatusCode)}
		return
	}

	resChan <- Result{Err: nil}
}

func main() {
	url := flag.String("url", "http://example.com", "URL to request")
	workers := flag.Int("workers", 5, "Number of concurrent workers")
	flag.Parse()

	resChan := make(chan Result, *workers)
	var wg sync.WaitGroup
	wg.Add(*workers)

	for i := 0; i < *workers; i++ {
		go func() {
			defer wg.Done()
			makeRequest(*url, resChan)
		}()
	}

	go func() {
		wg.Wait()
		close(resChan)
	}()

	var successes int
	var errors []error
	for res := range resChan {
		if res.Err == nil {
			successes++
		} else {
			errors = append(errors, res.Err)
		}
	}

	log.Printf("Total successful responses: %d", successes)
	log.Printf("Total errors: %d", len(errors))
	for _, err := range errors {
		log.Println("Error:", err)
	}
}
