package main

import (
	"sync"
)

func ConcurrentSum(numbers []int) int {
	const numSegments = 2
	segmentSize := len(numbers) / numSegments
	ch := make(chan int)
	var wg sync.WaitGroup

	for i := 0; i < numSegments; i++ {
		wg.Add(1)
		go func(i int) {
			defer wg.Done()
			start := i * segmentSize
			end := start + segmentSize
			if i == numSegments-1 {
				end = len(numbers)
			}
			sum := 0
			for _, num := range numbers[start:end] {
				sum += num
			}
			ch <- sum
		}(i)
	}

	go func() {
		wg.Wait()
		close(ch)
	}()

	total := 0
	for partial := range ch {
		total += partial
	}
	return total
}
